  1	import { beforeEach, describe, expect, it } from '@jest/globals';
  2	import type { V1beta1Plan } from '@kubev2v/types';
  3	import { render, screen } from '@testing-library/react';
  4	import { userEvent } from '@testing-library/user-event';
  5	
  6	import SetLUKSEncryptionPasswordsDetailsItem from '../SetLUKSEncryptionPasswordsDetailsItem';
  7	
  8	const mockIsPlanEditable = jest.fn();
  9	jest.mock('src/plans/details/components/PlanStatus/utils/utils', () => ({
 10	  isPlanEditable: jest.fn((...args) => mockIsPlanEditable(...args)),
 11	}));
 12	
 13	const mockShowModal = jest.fn();
 14	jest.mock('src/modules/Providers/modals/ModalHOC/useModal', () => ({
 15	  useModal: () => ({ showModal: mockShowModal }),
 16	}));
 17	
 18	// LUKSSecretLink is not mocked to test the real badge functionality
 19	
 20	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
 21	  getGroupVersionKindForModel: jest.fn(),
 22	  ResourceLink: ({ name }: { name: string }) => <span data-testid="resource-link">{name}</span>,
 23	}));
 24	
 25	jest.mock('../EditLUKSEncryptionPasswords', () => ({ resource }: { resource: V1beta1Plan }) => (
 26	  <div data-testid="edit-luks-modal">Modal for {resource.metadata?.name}</div>
 27	));
 28	
 29	const mockPlan = {
 30	  metadata: { name: 'test-plan', namespace: 'test-namespace' },
 31	  spec: { vms: [] },
 32	} as unknown as V1beta1Plan;
 33	
 34	describe('SetLUKSEncryptionPasswordsDetailsItem', () => {
 35	  beforeEach(() => {
 36	    jest.clearAllMocks();
 37	  });
 38	
 39	  it('renders nothing when shouldRender is false', () => {
 40	    const { container } = render(
 41	      <SetLUKSEncryptionPasswordsDetailsItem
 42	        canPatch={true}
 43	        plan={mockPlan}
 44	        shouldRender={false}
 45	      />,
 46	    );
 47	
 48	    expect(container.firstChild).toBeNull();
 49	  });
 50	
 51	  it('shows disk decryption title and no decryption keys label when no LUKS or NBDE', () => {
 52	    mockIsPlanEditable.mockReturnValue(true);
 53	
 54	    render(
 55	      <SetLUKSEncryptionPasswordsDetailsItem canPatch={true} plan={mockPlan} shouldRender={true} />,
 56	    );
 57	
 58	    expect(screen.getByText('Disk decryption')).toBeInTheDocument();
 59	    expect(screen.getByTestId('no-decryption-keys-label')).toBeInTheDocument();
 60	    expect(screen.getByText('No decryption defined')).toBeInTheDocument();
 61	  });
 62	
 63	  it('allows editing when permissions allow', async () => {
 64	    const user = userEvent.setup();
 65	    mockIsPlanEditable.mockReturnValue(true);
 66	
 67	    render(
 68	      <SetLUKSEncryptionPasswordsDetailsItem canPatch={true} plan={mockPlan} shouldRender={true} />,
 69	    );
 70	
 71	    const editButton = screen.getByRole('button', { name: '' });
 72	    expect(editButton).toBeEnabled();
 73	
 74	    await user.click(editButton);
 75	    expect(mockShowModal).toHaveBeenCalledTimes(1);
 76	  });
 77	
 78	  it('disables editing when canPatch is false', () => {
 79	    mockIsPlanEditable.mockReturnValue(true);
 80	
 81	    render(
 82	      <SetLUKSEncryptionPasswordsDetailsItem
 83	        canPatch={false}
 84	        plan={mockPlan}
 85	        shouldRender={true}
 86	      />,
 87	    );
 88	
 89	    expect(screen.getAllByRole('button')).toHaveLength(1); // Only the help button, no edit button
 90	  });
 91	
 92	  it('disables editing when plan is not editable', () => {
 93	    mockIsPlanEditable.mockReturnValue(false);
 94	
 95	    render(
 96	      <SetLUKSEncryptionPasswordsDetailsItem canPatch={true} plan={mockPlan} shouldRender={true} />,
 97	    );
 98	
 99	    expect(screen.getAllByRole('button')).toHaveLength(1); // Only the help button, no edit button
100	  });
101	
102	  it('shows NBDE/Clevis enabled label when NBDE is enabled', () => {
103	    mockIsPlanEditable.mockReturnValue(true);
104	    const planWithNBDE = {
105	      ...mockPlan,
106	      spec: { vms: [{ nbdeClevis: true }] },
107	    } as unknown as V1beta1Plan;
108	
109	    render(
110	      <SetLUKSEncryptionPasswordsDetailsItem
111	        canPatch={true}
112	        plan={planWithNBDE}
113	        shouldRender={true}
114	      />,
115	    );
116	
117	    expect(screen.getByText('Disk decryption')).toBeInTheDocument();
118	    expect(screen.getByTestId('nbde-clevis-enabled-label')).toBeInTheDocument();
119	    expect(screen.getByText('NBDE/Clevis enabled')).toBeInTheDocument();
120	  });
121	
122	  it('shows resource link when LUKS secret exists', () => {
123	    mockIsPlanEditable.mockReturnValue(true);
124	    const planWithLUKS = {
125	      ...mockPlan,
126	      spec: { vms: [{ luks: { name: 'test-secret' } }] },
127	    } as unknown as V1beta1Plan;
128	
129	    render(
130	      <SetLUKSEncryptionPasswordsDetailsItem
131	        canPatch={true}
132	        plan={planWithLUKS}
133	        shouldRender={true}
134	      />,
135	    );
136	
137	    expect(screen.getByText('Disk decryption')).toBeInTheDocument();
138	    expect(screen.getByTestId('resource-link')).toBeInTheDocument();
139	    expect(screen.getByText('test-secret')).toBeInTheDocument();
140	  });
141	
142	  it('prioritizes NBDE label over LUKS secret when both exist', () => {
143	    mockIsPlanEditable.mockReturnValue(true);
144	    const planWithBoth = {
145	      ...mockPlan,
146	      spec: { vms: [{ nbdeClevis: true, luks: { name: 'test-secret' } }] },
147	    } as unknown as V1beta1Plan;
148	
149	    render(
150	      <SetLUKSEncryptionPasswordsDetailsItem
151	        canPatch={true}
152	        plan={planWithBoth}
153	        shouldRender={true}
154	      />,
155	    );
156	
157	    expect(screen.getByText('Disk decryption')).toBeInTheDocument();
158	    expect(screen.getByTestId('nbde-clevis-enabled-label')).toBeInTheDocument();
159	    expect(screen.getByText('NBDE/Clevis enabled')).toBeInTheDocument();
160	    expect(screen.queryByTestId('resource-link')).not.toBeInTheDocument();
161	  });
162	});

