 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { VIRT_V2V_HELP_LINK } from '@utils/links';
 8	
 9	import type { EditableDetailsItemProps } from '../../../utils/types';
10	
11	import LUKSSecretLink from './components/LUKSSecretLink';
12	import EditLUKSEncryptionPasswords from './EditLUKSEncryptionPasswords';
13	
14	const SetLUKSEncryptionPasswordsDetailsItem: FC<EditableDetailsItemProps> = ({
15	  canPatch,
16	  plan,
17	  shouldRender,
18	}) => {
19	  const { t } = useForkliftTranslation();
20	  const { showModal } = useModal();
21	
22	  if (!shouldRender) return null;
23	
24	  return (
25	    <DetailsItem
26	      title={t('Disk decryption')}
27	      content={<LUKSSecretLink plan={plan} />}
28	      helpContent={t(
29	        'Configure disk decryption settings including passphrases for LUKS-encrypted devices or network-bound disk encryption (NBDE/Clevis) for the VMs you want to migrate.',
30	      )}
31	      moreInfoLink={VIRT_V2V_HELP_LINK}
32	      crumbs={['spec', 'vms', 'luks']}
33	      onEdit={() => {
34	        showModal(<EditLUKSEncryptionPasswords resource={plan} />);
35	      }}
36	      canEdit={canPatch && isPlanEditable(plan)}
37	    />
38	  );
39	};
40	export default SetLUKSEncryptionPasswordsDetailsItem;

